function transform (message, context) {
  const personId = context.get('__user').id;
  message.payload.personId = personId;
  return message;
}

function transform (message, context) {
  const person = message.payload.resPersons;
  const bannerId = person.credentials.find(c => c.type === "bannerId").value;
  message.payload.bannerId = bannerId;
  message.payload.resPersons = undefined;
  return message;
}

function transform(message, context) {
  const termCourses = message.payload.resStudentTermCourses;
  const gpaRecords  = message.payload.resStudentGpa;

  // ── Step 1: Build termData keyed by termCode, seeded from courses ──────────
  const termData = {};

  for (const course of termCourses) {
    const { termCode } = course;

    if (!termData[termCode]) {
      termData[termCode] = {
        courses:        [],
        term_gpa:       null,
        cumulative_gpa: null,
        gpa_available:  false,
      };
    }

    termData[termCode].courses.push(course);
  }

  // ── Step 2: Sort GPA records chronologically so cumulative runs correctly ──
  const sortedGpaRecords = [...gpaRecords].sort(
    (a, b) => Number(a.termCode) - Number(b.termCode)
  );

  // ── Step 3: Merge GPA data into termData ───────────────────────────────────
  let running_quality_points = 0;
  let running_gpa_hours      = 0;

  for (const record of sortedGpaRecords) {
    const { termCode, gpa, qualityPoints, gpaHours, levlCode } = record;

    running_quality_points += Number(qualityPoints || 0);
    running_gpa_hours      += Number(gpaHours      || 0);

    const cumulative_gpa =
      running_gpa_hours === 0 ? 0 : running_quality_points / running_gpa_hours;

    // Term may have a GPA record but no courses (edge case — be defensive)
    if (!termData[termCode]) {
      termData[termCode] = { courses: [] };
    }

    termData[termCode].term_gpa       = Number(gpa);
    termData[termCode].cumulative_gpa = cumulative_gpa;
    termData[termCode].gpa_available  = true;
  }

  // ── Step 4: For terms with no GPA record, carry forward last known CGPA ───
  // Sort all term keys chronologically for the carry-forward pass
  const allTermsSorted = Object.keys(termData).sort(
    (a, b) => Number(a) - Number(b)
  );

  let last_known_cumulative = null;

  for (const termCode of allTermsSorted) {
    if (termData[termCode].gpa_available) {
      last_known_cumulative = termData[termCode].cumulative_gpa;
    } else {
      // No GPA record for this term — carry forward but keep gpa_available: false
      // so the UI knows this is inherited, not real
      termData[termCode].cumulative_gpa = last_known_cumulative;
    }
  }

  // ── Step 5: Clean up and return ───────────────────────────────────────────
  message.payload.termData = termData;
  delete message.payload.resStudentTermCourses;
  delete message.payload.resStudentGpa;

  return message;
}
